"use client";

import { useState, useMemo, useCallback } from "react";
import type { CSSProperties, ReactNode } from "react";
import {
  Tooltip,
  TooltipTrigger,
  TooltipContent,
  TooltipProvider,
} from "@/components/ui/tooltip";

interface MenuOption {
  key: string;
  display: ReactNode | string;
  text?: string;
  disabled?: boolean;
  group?: boolean;
  children?: MenuOption[];
}

interface SSideMenuProps {
  className?: string;
  style?: CSSProperties;
  head?: ReactNode;
  showOverview?: boolean | ReactNode;
  showSearch?: boolean;
  menuOptions?: MenuOption[];
  onClickMenu?: (key: string) => void;
  collapse?: boolean;
  onCollapse?: (collapse: boolean) => void;
  selectedKeys?: string[];
  defaultSelectedKeys?: string[];
  width?: number;
}

function IconChevron({ expanded }: { expanded: boolean }) {
  return (
    <svg
      width="8"
      height="6"
      viewBox="0 0 8 6"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{
        transition: "transform 0.2s ease",
        transform: expanded ? "rotate(0deg)" : "rotate(-90deg)",
      }}
    >
      <path
        d="M1 1.5L4 4.5L7 1.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function IconFold() {
  return (
    <svg
      width="14"
      height="13"
      viewBox="0 0 14 13"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        fillRule="evenodd"
        clipRule="evenodd"
        d="M12.8953 8.56445C13.1143 8.56446 13.2919 8.74202 13.2919 8.96105L13.2918 12.3723C13.2918 12.4445 13.2721 12.5152 13.2348 12.577C13.1218 12.7646 12.878 12.825 12.6904 12.7119L9.86108 11.0064C9.80581 10.9731 9.7595 10.9268 9.72618 10.8715C9.6131 10.6839 9.6735 10.4402 9.86108 10.3271L12.6905 8.62139C12.7523 8.58414 12.8231 8.56445 12.8953 8.56445ZM7 10C7.18409 10 7.33333 10.1492 7.33333 10.3333V11C7.33333 11.1841 7.18409 11.3333 7 11.3333H0.333333C0.149238 11.3333 0 11.1841 0 11V10.3333C0 10.1492 0.149238 10 0.333333 10H7ZM11.6667 5C11.8508 5 12 5.14924 12 5.33333V6C12 6.18409 11.8508 6.33333 11.6667 6.33333H0.333333C0.149238 6.33333 0 6.18409 0 6V5.33333C0 5.14924 0.149238 5 0.333333 5H11.6667ZM11.6667 0C11.8508 0 12 0.149238 12 0.333333V1C12 1.18409 11.8508 1.33333 11.6667 1.33333H0.333333C0.149238 1.33333 0 1.18409 0 1V0.333333C0 0.149238 0.149238 0 0.333333 0H11.6667Z"
        fill="currentColor"
      />
    </svg>
  );
}

function IconUnfold() {
  return (
    <svg
      width="14"
      height="14"
      viewBox="0 0 14 14"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        fillRule="evenodd"
        clipRule="evenodd"
        d="M0.417707 9.17969C0.187009 9.17969 -4.76837e-06 9.35725 0 9.57628L8.39233e-05 12.9875C8.58307e-05 13.0597 0.0208206 13.1305 0.0600557 13.1923C0.179156 13.3798 0.435875 13.4402 0.633452 13.3272L3.61355 11.6216C3.67177 11.5883 3.72054 11.542 3.75564 11.4867C3.87474 11.2991 3.81113 11.0554 3.61355 10.9423L0.633377 9.23663C0.568283 9.19937 0.493715 9.17968 0.417707 9.17969ZM6.62706 10.6152C6.43316 10.6152 6.27597 10.7645 6.27597 10.9486V11.6152C6.27597 11.7993 6.43316 11.9486 6.62706 11.9486H13.6489C13.8428 11.9486 14 11.7993 14 11.6152V10.9486C14 10.7645 13.8428 10.6152 13.6489 10.6152H6.62706ZM1.71177 5.61523C1.51787 5.61523 1.36068 5.76447 1.36068 5.94857V6.61523C1.36068 6.79933 1.51787 6.94857 1.71177 6.94857H13.6489C13.8428 6.94857 14 6.79933 14 6.61523V5.94857C14 5.76447 13.8428 5.61523 13.6489 5.61523H1.71177ZM1.71177 0.615234C1.51787 0.615234 1.36068 0.764473 1.36068 0.948568V1.61523C1.36068 1.79933 1.51787 1.94857 1.71177 1.94857H13.6489C13.8428 1.94857 14 1.79933 14 1.61523V0.948568C14 0.764473 13.8428 0.615234 13.6489 0.615234H1.71177Z"
        fill="currentColor"
      />
    </svg>
  );
}

function IconOverview() {
  return (
    <svg
      width="20"
      height="20"
      viewBox="-1 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M0.664062 6.86143V8.41904C0.664062 8.81119 1.10883 9.03786 1.42613 8.80742L8.7783 3.46772C8.94411 3.3473 9.16809 3.34542 9.33589 3.46306L16.7538 8.66306C17.0719 8.88605 17.5094 8.65849 17.5094 8.27001V7.08147C17.5094 6.9282 17.4362 6.78415 17.3124 6.69378L9.3343 0.869599C9.1677 0.747975 8.94202 0.746393 8.77373 0.865667L0.866509 6.46981C0.739526 6.55981 0.664062 6.70579 0.664062 6.86143Z"
        fill="#9FAABA"
      />
      <path
        d="M16.1763 9.8294L16.1763 16.7469C16.1763 17.012 15.9614 17.2269 15.6963 17.2269H12.0135H6.1628H2.48002C2.21493 17.2269 2.00003 17.012 2.00002 16.7469L2.00001 9.8294C2.00001 9.67605 2.07328 9.53193 2.19718 9.44158L8.80531 4.62229C8.97384 4.49938 9.20245 4.49938 9.37098 4.62229L15.9791 9.44158C16.103 9.53194 16.1763 9.67605 16.1763 9.8294Z"
        fill="#5E6673"
      />
      <rect x="6.08594" y="13.584" width="5.83333" height="1.25" fill="white" />
    </svg>
  );
}

function IconSearch() {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 16 16"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M7.333 12.667A5.333 5.333 0 107.333 2a5.333 5.333 0 000 10.667zM14 14l-2.9-2.9"
        stroke="currentColor"
        strokeWidth="1.33"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function collectAllItems(options: MenuOption[]): MenuOption[] {
  const result: MenuOption[] = [];
  for (const opt of options) {
    if (!opt.group) {
      result.push(opt);
    }
    if (opt.children) {
      result.push(...collectAllItems(opt.children));
    }
  }
  return result;
}

function filterOptions(
  options: MenuOption[],
  query: string
): MenuOption[] {
  const q = query.toLowerCase();
  const result: MenuOption[] = [];
  for (const opt of options) {
    if (opt.children && opt.children.length > 0) {
      const filteredChildren = filterOptions(opt.children, query);
      if (filteredChildren.length > 0) {
        result.push({ ...opt, children: filteredChildren });
      }
    } else {
      const matchText = opt.text || (typeof opt.display === "string" ? opt.display : "");
      if (matchText.toLowerCase().includes(q)) {
        result.push(opt);
      }
    }
  }
  return result;
}

function MenuItemRow({
  option,
  level,
  isCollapsed,
  isSelected,
  onClick,
  selectedKeys,
  onClickMenu,
  expandedKeys,
  toggleExpand,
}: {
  option: MenuOption;
  level: number;
  isCollapsed: boolean;
  isSelected: boolean;
  onClick: () => void;
  selectedKeys: string[];
  onClickMenu?: (key: string) => void;
  expandedKeys: Set<string>;
  toggleExpand: (key: string) => void;
}) {
  const [hovered, setHovered] = useState(false);
  const hasChildren = option.children && option.children.length > 0 && !option.group;
  const isGroup = option.group && option.children && option.children.length > 0;
  const isExpanded = expandedKeys.has(option.key);

  if (isGroup) {
    return (
      <div>
        {!isCollapsed && (
          <div
            style={{
              padding: "8px 12px 4px",
              paddingLeft: 12 + level * 32,
              fontSize: 12,
              fontWeight: 500,
              color: "var(--color-text-3)",
              lineHeight: "20px",
              userSelect: "none",
            }}
          >
            {option.display}
          </div>
        )}
        {option.children!.map((child) => (
          <MenuItemRow
            key={child.key}
            option={child}
            level={isCollapsed ? 0 : level + 1}
            isCollapsed={isCollapsed}
            isSelected={selectedKeys.includes(child.key)}
            onClick={() => {
              if (!child.disabled) {
                onClickMenu?.(child.key);
              }
            }}
            selectedKeys={selectedKeys}
            onClickMenu={onClickMenu}
            expandedKeys={expandedKeys}
            toggleExpand={toggleExpand}
          />
        ))}
      </div>
    );
  }

  if (hasChildren) {
    const itemContent = (
      <div>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            padding: isCollapsed ? "8px 0" : "8px 12px",
            paddingLeft: isCollapsed ? 0 : 12 + level * 32,
            cursor: option.disabled ? "not-allowed" : "pointer",
            opacity: option.disabled ? 0.5 : 1,
            backgroundColor: hovered ? "var(--color-fill-2)" : "transparent",
            borderRadius: 4,
            margin: "0 4px",
            transition: "background-color 0.15s ease",
            fontSize: 14,
            lineHeight: "22px",
            color: "var(--color-text-1)",
            userSelect: "none",
          }}
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => setHovered(false)}
          onClick={() => {
            if (!option.disabled) {
              toggleExpand(option.key);
            }
          }}
        >
          {isCollapsed ? (
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                width: "100%",
              }}
            >
              <IconChevron expanded={isExpanded} />
            </div>
          ) : (
            <>
              <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                {option.display}
              </span>
              <span
                style={{
                  display: "flex",
                  alignItems: "center",
                  marginLeft: 4,
                  color: "var(--color-text-3)",
                }}
              >
                <IconChevron expanded={isExpanded} />
              </span>
            </>
          )}
        </div>
        {isExpanded && !isCollapsed && (
          <div>
            {option.children!.map((child) => (
              <MenuItemRow
                key={child.key}
                option={child}
                level={level + 1}
                isCollapsed={isCollapsed}
                isSelected={selectedKeys.includes(child.key)}
                onClick={() => {
                  if (!child.disabled) {
                    onClickMenu?.(child.key);
                  }
                }}
                selectedKeys={selectedKeys}
                onClickMenu={onClickMenu}
                expandedKeys={expandedKeys}
                toggleExpand={toggleExpand}
              />
            ))}
          </div>
        )}
      </div>
    );

    if (isCollapsed) {
      return (
        <TooltipProvider>
          <Tooltip>
            <TooltipTrigger
              style={{ display: "block", width: "100%" }}
            >
              {itemContent}
            </TooltipTrigger>
            <TooltipContent side="right">
              {option.text || (typeof option.display === "string" ? option.display : option.key)}
            </TooltipContent>
          </Tooltip>
        </TooltipProvider>
      );
    }

    return itemContent;
  }

  const leafContent = (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        padding: isCollapsed ? "8px 0" : "8px 12px",
        paddingLeft: isCollapsed ? 0 : 12 + level * 32,
        cursor: option.disabled ? "not-allowed" : "pointer",
        opacity: option.disabled ? 0.5 : 1,
        backgroundColor: isSelected
          ? "var(--color-primary-light-1)"
          : hovered
            ? "var(--color-fill-2)"
            : "transparent",
        color: isSelected ? "var(--primary-6)" : "var(--color-text-1)",
        fontWeight: isSelected ? 500 : 400,
        borderRadius: 4,
        margin: "0 4px",
        transition: "background-color 0.15s ease, color 0.15s ease",
        fontSize: 14,
        lineHeight: "22px",
        userSelect: "none",
        overflow: "hidden",
        textOverflow: "ellipsis",
        whiteSpace: "nowrap",
        justifyContent: isCollapsed ? "center" : "flex-start",
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={() => {
        if (!option.disabled) {
          onClick();
        }
      }}
    >
      {isCollapsed ? (
        <span style={{ fontSize: 14 }}>
          {typeof option.display === "string"
            ? option.display.charAt(0)
            : option.key.charAt(0).toUpperCase()}
        </span>
      ) : (
        <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
          {option.display}
        </span>
      )}
    </div>
  );

  if (isCollapsed) {
    return (
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger style={{ display: "block", width: "100%" }}>
            {leafContent}
          </TooltipTrigger>
          <TooltipContent side="right">
            {option.text || (typeof option.display === "string" ? option.display : option.key)}
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>
    );
  }

  return leafContent;
}

const SSideMenu = (props: SSideMenuProps) => {
  const {
    className,
    style,
    head,
    showOverview = false,
    showSearch = true,
    menuOptions = [],
    onClickMenu,
    collapse: controlledCollapse,
    onCollapse,
    selectedKeys: controlledSelectedKeys,
    defaultSelectedKeys = [],
    width = 200,
  } = props;

  const [internalCollapse, setInternalCollapse] = useState(false);
  const isCollapseControlled = controlledCollapse !== undefined;
  const isCollapsed = isCollapseControlled ? controlledCollapse : internalCollapse;

  const [internalSelectedKeys, setInternalSelectedKeys] =
    useState<string[]>(defaultSelectedKeys);
  const isSelectedControlled = controlledSelectedKeys !== undefined;
  const selectedKeys = isSelectedControlled
    ? controlledSelectedKeys
    : internalSelectedKeys;

  const [searchValue, setSearchValue] = useState("");
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  const toggleExpand = useCallback((key: string) => {
    setExpandedKeys((prev) => {
      const next = new Set(prev);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.add(key);
      }
      return next;
    });
  }, []);

  const handleClickMenu = useCallback(
    (key: string) => {
      if (!isSelectedControlled) {
        setInternalSelectedKeys([key]);
      }
      onClickMenu?.(key);
    },
    [isSelectedControlled, onClickMenu]
  );

  const toggleCollapse = useCallback(() => {
    const next = !isCollapsed;
    if (!isCollapseControlled) {
      setInternalCollapse(next);
    }
    onCollapse?.(next);
  }, [isCollapsed, isCollapseControlled, onCollapse]);

  const displayOptions = useMemo(() => {
    if (!searchValue.trim()) return menuOptions;
    return filterOptions(menuOptions, searchValue.trim());
  }, [menuOptions, searchValue]);

  const allItems = useMemo(() => collectAllItems(menuOptions), [menuOptions]);

  const currentWidth = isCollapsed ? 48 : width;

  const overviewNode = useMemo(() => {
    if (showOverview === false) return null;
    if (showOverview === true) {
      const isOverviewSelected = selectedKeys.includes("__overview__");
      return (
        <OverviewItem
          isCollapsed={isCollapsed}
          isSelected={isOverviewSelected}
          onClick={() => handleClickMenu("__overview__")}
        />
      );
    }
    return showOverview;
  }, [showOverview, isCollapsed, selectedKeys, handleClickMenu]);

  return (
    <div
      className={className}
      style={{
        width: currentWidth,
        height: "100%",
        display: "flex",
        flexDirection: "column",
        backgroundColor: "var(--color-bg-2)",
        borderRight: "1px solid var(--color-border)",
        transition: "width 0.2s ease",
        overflow: "hidden",
        ...style,
      }}
    >
      {head && !isCollapsed && (
        <div
          style={{
            padding: "12px",
            borderBottom: "1px solid var(--color-border)",
            flexShrink: 0,
          }}
        >
          {head}
        </div>
      )}

      {overviewNode}

      {showSearch && !isCollapsed && (
        <div style={{ padding: "8px 8px 0", flexShrink: 0 }}>
          <div
            style={{
              position: "relative",
              display: "flex",
              alignItems: "center",
            }}
          >
            <span
              style={{
                position: "absolute",
                left: 8,
                display: "flex",
                alignItems: "center",
                color: "var(--color-text-3)",
                pointerEvents: "none",
              }}
            >
              <IconSearch />
            </span>
            <input
              value={searchValue}
              onChange={(e) => setSearchValue(e.target.value)}
              placeholder="搜索"
              style={{
                width: "100%",
                height: 32,
                paddingLeft: 30,
                paddingRight: 8,
                border: "1px solid var(--color-border)",
                borderRadius: 4,
                backgroundColor: "var(--color-fill-1)",
                color: "var(--color-text-1)",
                fontSize: 14,
                outline: "none",
                boxSizing: "border-box",
              }}
            />
          </div>
        </div>
      )}

      <div
        style={{
          flex: 1,
          overflowY: "auto",
          overflowX: "hidden",
          padding: "4px 0",
        }}
      >
        {displayOptions.map((option) => (
          <MenuItemRow
            key={option.key}
            option={option}
            level={0}
            isCollapsed={isCollapsed}
            isSelected={selectedKeys.includes(option.key)}
            onClick={() => {
              if (!option.disabled) {
                handleClickMenu(option.key);
              }
            }}
            selectedKeys={selectedKeys}
            onClickMenu={handleClickMenu}
            expandedKeys={expandedKeys}
            toggleExpand={toggleExpand}
          />
        ))}
        {searchValue.trim() && displayOptions.length === 0 && !isCollapsed && (
          <div
            style={{
              padding: "16px 12px",
              textAlign: "center",
              color: "var(--color-text-3)",
              fontSize: 13,
            }}
          >
            无匹配结果
          </div>
        )}
      </div>

      <CollapseButton isCollapsed={isCollapsed} onClick={toggleCollapse} />
    </div>
  );
};

function OverviewItem({
  isCollapsed,
  isSelected,
  onClick,
}: {
  isCollapsed: boolean;
  isSelected: boolean;
  onClick: () => void;
}) {
  const [hovered, setHovered] = useState(false);

  const content = (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: isCollapsed ? 0 : 8,
        padding: isCollapsed ? "8px 0" : "8px 12px",
        margin: "4px 4px 0",
        cursor: "pointer",
        backgroundColor: isSelected
          ? "var(--color-primary-light-1)"
          : hovered
            ? "var(--color-fill-2)"
            : "transparent",
        color: isSelected ? "var(--primary-6)" : "var(--color-text-1)",
        fontWeight: isSelected ? 500 : 400,
        borderRadius: 4,
        transition: "background-color 0.15s ease",
        fontSize: 14,
        lineHeight: "22px",
        justifyContent: isCollapsed ? "center" : "flex-start",
        userSelect: "none",
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={onClick}
    >
      <IconOverview />
      {!isCollapsed && <span>概览</span>}
    </div>
  );

  if (isCollapsed) {
    return (
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger style={{ display: "block", width: "100%" }}>
            {content}
          </TooltipTrigger>
          <TooltipContent side="right">概览</TooltipContent>
        </Tooltip>
      </TooltipProvider>
    );
  }

  return content;
}

function CollapseButton({
  isCollapsed,
  onClick,
}: {
  isCollapsed: boolean;
  onClick: () => void;
}) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      style={{
        flexShrink: 0,
        borderTop: "1px solid var(--color-border)",
        padding: "8px",
        display: "flex",
        justifyContent: isCollapsed ? "center" : "flex-end",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          width: 28,
          height: 28,
          borderRadius: 4,
          cursor: "pointer",
          backgroundColor: hovered ? "var(--color-fill-2)" : "transparent",
          color: "var(--color-text-2)",
          transition: "background-color 0.15s ease",
        }}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        onClick={onClick}
      >
        {isCollapsed ? <IconUnfold /> : <IconFold />}
      </div>
    </div>
  );
}

export type { SSideMenuProps, MenuOption };
export default SSideMenu;
